const item = items[0]?.json || {};
const required = ['agent', 'workflow', 'status', 'intake_id', 'intake_kind', 'title', 'queue_stage', 'route_target', 'created_note_relative_path', 'downstream_workflow', 'downstream_status', 'escalate_to', 'reason', 'next_step'];
for (const key of required) {
  if (!(key in item)) throw new Error(`Missing required key: ${key}`);
}
const allowedStatus = new Set(['done', 'partial', 'blocked', 'needs_review', 'queued']);
if (!allowedStatus.has(item.status)) throw new Error(`Invalid status: ${item.status}`);
if (!allowedStatus.has(item.downstream_status)) throw new Error(`Invalid downstream_status: ${item.downstream_status}`);
const allowedKinds = new Set(['task', 'growth', 'research', 'handoff', 'truth_update_draft']);
if (!allowedKinds.has(item.intake_kind)) throw new Error(`Invalid intake_kind: ${item.intake_kind}`);
const allowedEscalation = new Set(['none', 'AI-1', 'AI-2', 'AI-3', 'AI-5', 'AI-6', 'AI-7', 'AI-8', 'AI-9', 'AI-10', 'AI-11', 'Owner']);
if (!allowedEscalation.has(item.route_target)) throw new Error(`Invalid route_target: ${item.route_target}`);
if (!allowedEscalation.has(item.escalate_to)) throw new Error(`Invalid escalate_to: ${item.escalate_to}`);
item.execution_summary = {
  note_created: item.writeback?.status || 'unknown',
  downstream: item.downstream_workflow,
  downstream_status: item.downstream_status,
  next_step: item.next_step
};
return [{ json: item }];
